"use strict";(()=>{var e={};e.id=317,e.ids=[317],e.modules={399:e=>{e.exports=require("next/dist/compiled/next-server/app-page.runtime.prod.js")},517:e=>{e.exports=require("next/dist/compiled/next-server/app-route.runtime.prod.js")},4763:(e,t,r)=>{r.r(t),r.d(t,{originalPathname:()=>v,patchFetch:()=>g,requestAsyncStorage:()=>l,routeModule:()=>c,serverHooks:()=>m,staticGenerationAsyncStorage:()=>p});var s={};r.r(s),r.d(s,{GET:()=>d});var n=r(9303),a=r(8716),o=r(670),i=r(7070);let u=[{id:"1",authorId:"4",title:"Comment trouver un logement abordable \xe0 Vellore ?",content:"Je viens d'arriver \xe0 VELLORE et je cherche un appartement. Quelqu'un peut me recommander des quartiers s\xfbrs et abordables pr\xe8s de VIT ? Mon budget est de 8,000-12,000 INR/mois.",tags:["logement","Vellore","VIT"],answers:[{id:"a1",authorId:"1",content:"Salut Efua ! Je te recommande le quartier de Katpadi, c'est proche de VIT et les loyers sont raisonnables. \xc9vite les agents, cherche directement avec les propri\xe9taires. Contacte-moi en priv\xe9, j'ai des contacts.",votes:12,isAccepted:!0,createdAt:"2024-12-10T10:00:00Z"},{id:"a2",authorId:"6",content:"\xc0 Manipal, j'ai trouv\xe9 mon appartement sur Housing.com. V\xe9rifie aussi les groupes Facebook pour \xe9tudiants internationaux.",votes:5,isAccepted:!1,createdAt:"2024-12-10T12:00:00Z"}],votes:8,createdAt:"2024-12-10T08:00:00Z",resolved:!0},{id:"2",authorId:"9",title:"Conseils pour pr\xe9parer les examens de droit \xe0 NLSIU ?",content:"Je suis en premi\xe8re ann\xe9e de droit \xe0 NLSIU Bangalore. Les examens approchent et je suis un peu stress\xe9. Les anciens \xe9tudiants ont-ils des conseils pour bien r\xe9viser ? Surtout pour Constitutional Law et Contracts.",tags:["droit","NLSIU","examens","r\xe9vision"],answers:[{id:"a3",authorId:"8",content:"Pour Constitutional Law, je recommande de lire les jugements originaux plut\xf4t que les r\xe9sum\xe9s. Fais des fiches de jurisprudence. Pour Contracts, comprends bien les concepts avant de m\xe9moriser.",votes:7,isAccepted:!1,createdAt:"2024-12-09T15:00:00Z"}],votes:5,createdAt:"2024-12-09T14:00:00Z",resolved:!1},{id:"3",authorId:"10",title:"Comment obtenir un visa de travail apr\xe8s les \xe9tudes en Inde ?",content:"Je termine mon Master en \xc9conomie \xe0 Delhi School of Economics. Quelqu'un a de l'exp\xe9rience avec le processus de visa de travail en Inde ? Est-ce que c'est difficile pour les \xe9tudiants africains ?",tags:["visa","travail","post-\xe9tudes"],answers:[{id:"a4",authorId:"5",content:"Apr\xe8s tes \xe9tudes, tu peux demander un Employment Visa si tu as une offre d'emploi. Le processus est le m\xeame pour tous les \xe9trangers. Le plus important c'est d'avoir un employeur qui te sponsorise. Je te recommande de commencer \xe0 chercher du travail 6 mois avant la fin de tes \xe9tudes.",votes:15,isAccepted:!0,createdAt:"2024-12-08T11:00:00Z"},{id:"a5",authorId:"3",content:"Tu peux aussi explorer le visa d'affaires si tu veux cr\xe9er une startup. Le Startup India programme facilite les choses pour les entrepreneurs \xe9trangers.",votes:8,isAccepted:!1,createdAt:"2024-12-08T13:00:00Z"}],votes:20,createdAt:"2024-12-08T09:00:00Z",resolved:!0},{id:"4",authorId:"7",title:"Meilleures banques pour \xe9tudiants internationaux en Inde ?",content:"Quelle banque recommandez-vous pour ouvrir un compte en tant qu'\xe9tudiant international ? J'ai besoin d'une bonne appli mobile et de frais de transfert bas pour envoyer de l'argent au Togo.",tags:["banque","finance","transfert"],answers:[{id:"a6",authorId:"1",content:"HDFC Bank est tr\xe8s bien pour les \xe9tudiants. L'appli est bonne et ils ont un service client en anglais. Pour les transferts internationaux, Wise (ex-TransferWise) est le moins cher.",votes:10,isAccepted:!1,createdAt:"2024-12-07T14:00:00Z"}],votes:12,createdAt:"2024-12-07T10:00:00Z",resolved:!1},{id:"5",authorId:"6",title:"Comment cuisiner de la nourriture togolaise en Inde ?",content:"Je meurs d'envie de manger du fufu et du djenkoum\xe9 mais je ne trouve pas les ingr\xe9dients \xe0 Manipal. Quelqu'un a des astuces pour adapter les recettes togolaises avec des ingr\xe9dients indiens ?",tags:["cuisine","nourriture","adaptation"],answers:[{id:"a7",authorId:"2",content:"Pour le fufu, utilise de la farine de bl\xe9 indienne (atta) m\xe9lang\xe9e avec de la farine de plantain. Tu peux trouver du plantain dans les march\xe9s locaux. Pour le piment, le piment vert indien fonctionne tr\xe8s bien !",votes:18,isAccepted:!0,createdAt:"2024-12-06T16:00:00Z"},{id:"a8",authorId:"4",content:"Il y a un magasin africain \xe0 Bangalore qui vend des ingr\xe9dients togolais ! Je peux te partager l'adresse en priv\xe9.",votes:6,isAccepted:!1,createdAt:"2024-12-06T18:00:00Z"}],votes:25,createdAt:"2024-12-06T14:00:00Z",resolved:!0}];async function d(){return i.NextResponse.json(u)}let c=new n.AppRouteRouteModule({definition:{kind:a.x.APP_ROUTE,page:"/api/forum/route",pathname:"/api/forum",filename:"route",bundlePath:"app/api/forum/route"},resolvedPagePath:"C:\\Users\\LENOVO\\Desktop\\DEV\\Agent_Secret_SRM\\src\\app\\api\\forum\\route.ts",nextConfigOutput:"",userland:s}),{requestAsyncStorage:l,staticGenerationAsyncStorage:p,serverHooks:m}=c,v="/api/forum/route";function g(){return(0,o.patchFetch)({serverHooks:m,staticGenerationAsyncStorage:p})}}};var t=require("../../../webpack-runtime.js");t.C(e);var r=e=>t(t.s=e),s=t.X(0,[276,972],()=>r(4763));module.exports=s})();